mapper.select:
/* CodeMapper.selectCodeGroupList */ SELECT group_cd, group_nm, group_desc, use_yn, reg_id, reg_dt, upd_id, upd_dt FROM tb_code_group WHERE 1=1
AND ( group_cd LIKE '%' || #{groupNm} || '%' OR group_nm LIKE '%' || #{groupNm} || '%' )
ORDER BY reg_dt DESC

/* CodeMapper.selectCodeGroup */
SELECT 
	group_cd, group_nm, group_desc, use_yn, reg_id, reg_dt, upd_id, upd_dt
FROM tb_code_group
WHERE group_cd = #{groupCd}

mapper.insert:
/* CodeMapper.insertCodeGroup */
INSERT INTO tb_code_group (
	group_cd, group_nm, group_desc, use_yn, reg_id, reg_dt
) VALUES (
	#{groupCd}, #{groupNm}, #{groupDesc}, 'Y', #{regId}, TO_CHAR(NOW(), 'YYYYMMDDHH24MISS')
)

mapper.update:
/* CodeMapper.updateCodeGroup */
UPDATE tb_code_group
SET group_nm = #{groupNm}
	, group_desc = #{groupDesc}
	, use_yn = #{useYn}
	, upd_id = #{updId}
	, upd_dt = TO_CHAR(NOW(), 'YYYYMMDDHH24MISS')
WHERE group_cd = #{groupCd}

/* CodeMapper.deleteCodeGroup */
UPDATE tb_code_group
SET use_yn = 'N'
	, upd_id = #{updId}
	, upd_dt = TO_CHAR(NOW(), 'YYYYMMDDHH24MISS')
WHERE group_cd = #{groupCd}

mapper.select:
/* CodeMapper.selectCodeDetailList */
SELECT 
	group_cd, detail_cd, code_nm, code_desc, sort_order, use_yn, reg_id, reg_dt, upd_id, upd_dt
FROM tb_code_detail
WHERE group_cd = #{groupCd}

	AND use_yn = #{useYn}

ORDER BY sort_order ASC, detail_cd ASC

/* CodeMapper.selectCodeDetail */
SELECT 
	group_cd, detail_cd, code_nm, code_desc, sort_order, use_yn, reg_id, reg_dt, upd_id, upd_dt
FROM tb_code_detail
WHERE group_cd = #{groupCd}
AND detail_cd = #{detailCd}

mapper.insert:
/* CodeMapper.insertCodeDetail */
INSERT INTO tb_code_detail (
	group_cd, detail_cd, code_nm, code_desc, sort_order, use_yn, reg_id, reg_dt
) VALUES (
	#{groupCd}, #{detailCd}, #{codeNm}, #{codeDesc}, #{sortOrder}, 'Y', #{regId}, TO_CHAR(NOW(), 'YYYYMMDDHH24MISS')
)

mapper.update:
/* CodeMapper.updateCodeDetail */
UPDATE tb_code_detail
SET code_nm = #{codeNm}
	, code_desc = #{codeDesc}
	, sort_order = #{sortOrder}
	, use_yn = #{useYn}
	, upd_id = #{updId}
	, upd_dt = TO_CHAR(NOW(), 'YYYYMMDDHH24MISS')
WHERE group_cd = #{groupCd}
AND detail_cd = #{detailCd}

/* CodeMapper.deleteCodeDetail */
UPDATE tb_code_detail
SET use_yn = 'N'
	, upd_id = #{updId}
	, upd_dt = TO_CHAR(NOW(), 'YYYYMMDDHH24MISS')
WHERE group_cd = #{groupCd}
AND detail_cd = #{detailCd}
